export const Providers: React.FC<{
  children: React.ReactNode
}> = ({ children }) => {
  return (
    <ThemeProvider>
      <AnalyticsProvider>
        <HeaderThemeProvider>{children}</HeaderThemeProvider>
      </AnalyticsProvider>
    </ThemeProvider>
  )
}

import * as React from 'react'
import { cn } from '@/infra/utils/ui'

interface ProgressProps extends React.HTMLAttributes<HTMLDivElement> {
  value?: number
}

const Progress = React.forwardRef<HTMLDivElement, ProgressProps>(
  ({ className, value = 0, ...props }, ref) => (
    <div ref={ref} className={cn('relative w-full overflow-hidden bg-muted', className)} {...props}>
      <div
        className="h-full bg-primary transition-all duration-700 ease-out"
        style={{ width: `${Math.min(100, Math.max(0, value))}%` }}
      />
    </div>
  ),
)
Progress.displayName = 'Progress'

export { Progress }

import type { Access } from 'payload'

import { AccountRole } from '@/server/payload/collections/Users/roles'
import { isUsersCollectionUser } from '@/server/payload/access/isUsersCollectionUser'

/**
 * Access control that allows admins to access all records,
 * or authenticated users to access their own records (query constraint)
 */
export const authenticatedOrOwner: Access = ({ req: { user } }) => {
  if (!isUsersCollectionUser(user)) return false

  // Admins can access all records
  if (user.role === AccountRole.Admin) return true

  // Users can only access their own records
  return {
    user: { equals: user.id },
  }
}

}

// Validate DATABASE_URL is set and not empty
// This prevents accidental fallback to localhost when Atlas connection string is expected
const databaseUrl = process.env.DATABASE_URL
if (!databaseUrl || databaseUrl.trim() === '') {
  throw new Error(
    'DATABASE_URL environment variable is required but not set. ' +
      'Please set DATABASE_URL to your MongoDB connection string (e.g., mongodb+srv://... for Atlas).',
  )
}

const mcpEnabled = process.env.MCP_ENABLED === 'true'
if (
  mcpEnabled &&
  (!process.env.DEFAULT_TENANT_SLUG || process.env.DEFAULT_TENANT_SLUG.trim() === '')
) {
  throw new Error('DEFAULT_TENANT_SLUG environment variable is required when MCP_ENABLED=true.')
}

